import hashlib
import secrets
from cryptography.fernet import Fernet

def encrypt_user_data(data, encryption_key=None):
    """
    Encrypts sensitive user data before storing in database
    """
    if encryption_key is None:
        # Generate a new encryption key if none provided
        encryption_key = Fernet.generate_key()
    
    fernet = Fernet(encryption_key)
    
    # Hash the data for integrity check
    data_hash = hashlib.sha256(data.encode()).hexdigest()
    
    # Encrypt the actual data
    encrypted_data = fernet.encrypt(data.encode())
    
    return {
        'encrypted_data': encrypted_data,
        'data_hash': data_hash,
        'encryption_key': encryption_key
    }

def decrypt_user_data(encrypted_data, encryption_key):
    """
    Decrypts user data when retrieving from database
    """
    fernet = Fernet(encryption_key)
    decrypted_data = fernet.decrypt(encrypted_data)
    return decrypted_data.decode()

def hash_password(password):
    """
    Hashes password for secure storage
    """
    salt = secrets.token_hex(16)
    password_hash = hashlib.pbkdf2_hmac('sha256', password.encode(), salt.encode(), 100000)
    return salt + password_hash.hex()